var parsed = mermaid.parseMermaid("classDiagram\n  class Animal");
if (!parsed.ok) throw new Error("parse failed: " + JSON.stringify(parsed.error));
var classDiagram = mermaid.asClass(parsed.value);
if (!classDiagram) throw new Error("not a structured class diagram");
var mutated = mermaid.mutate(classDiagram, { kind: "add_class", id: "Duck", members: ["+quack()"] });
if (!mutated.ok) throw new Error("mutation failed: " + mutated.error.code + ": " + mutated.error.message);
var verified = mermaid.verifyMermaid(mutated.value);
if (!verified.ok) throw new Error("verify failed: " + JSON.stringify(verified.warnings));
if (!verified.layout || verified.layout.kind !== "class") throw new Error("verify layout missing");
return mermaid.serializeMermaid(mutated.value);

